// Scoring determinista segun spec.
function computeScore({ intencion, plazo, presupuesto, override_caliente }) {
  if (override_caliente) return 'CALIENTE';
  const plazoHot = ['ahora', '1_a_3_meses'].includes(plazo);
  const plazoWarm = ['3_a_6_meses', '6_a_12_meses'].includes(plazo);
  const intencionDef = intencion && intencion !== 'no_definido' && intencion !== 'evaluando';
  const presupuestoDef = presupuesto && presupuesto !== 'no_definido';
  if (plazoHot && intencionDef && presupuestoDef) return 'CALIENTE';
  if (plazoHot && (intencionDef || presupuestoDef)) return 'CALIENTE';
  if (plazoWarm && intencionDef && presupuestoDef) return 'TIBIO';
  if (plazoWarm) return 'TIBIO';
  return 'FRIO';
}

const d = $json;
const score = computeScore({
  intencion: d.intencion,
  plazo: d.plazo,
  presupuesto: d.presupuesto,
  override_caliente: !!d.override_caliente,
});

// Validaciones minimas
if (!d.nombre || typeof d.nombre !== 'string' || d.nombre.length < 1) {
  throw new Error('nombre requerido');
}
if (!d.session_id) {
  throw new Error('session_id requerido');
}

// Concatenar nombre + apellido para almacenamiento
const nombreCompleto = [d.nombre, d.apellido].filter(Boolean).join(' ').trim().slice(0, 150);

return [{ json: {
  session_id: d.session_id,
  nombre: nombreCompleto,
  whatsapp: d.whatsapp ? d.whatsapp.toString().slice(0, 30) : null,
  email: d.email ? d.email.toString().slice(0, 120) : null,
  intencion: d.intencion || 'no_definido',
  plazo: d.plazo || 'no_definido',
  presupuesto: d.presupuesto || 'no_definido',
  resumen: (d.resumen_conversacion || '').toString().slice(0, 800),
  score,
} }];

const scored = $('Compute Score').first().json;
const upsertResponse = $json;
let lead_id = null;
if (Array.isArray(upsertResponse) && upsertResponse.length > 0) {
  lead_id = upsertResponse[0].id;
} else if (upsertResponse.id) {
  lead_id = upsertResponse.id;
}

return [{ json: {
  lead_id,
  score: scored.score,
  nombre: scored.nombre,
  whatsapp: scored.whatsapp,
  email: scored.email,
  intencion: scored.intencion,
  plazo: scored.plazo,
  presupuesto: scored.presupuesto,
  resumen: scored.resumen,
  session_id: scored.session_id,
} }];

const scored = $('Compute Score').first().json;
const prepared = $('Prepare Notif Payload').first().json;
const notif = $json;

const primerNombre = scored.nombre.split(' ')[0];

return [{ json: {
  lead_id: prepared.lead_id,
  score: scored.score,
  notificado: !!notif.notified,
  tool_output_text: scored.score === 'CALIENTE'
    ? `Listo, ${primerNombre}. Ya le pase tu informacion al equipo de ventas. Te van a escribir por WhatsApp en las proximas horas (lun-vie 9-19). Si quieres adelantarte, tambien puedes escribirles tu al +56 9 4032 9987.`
    : scored.score === 'TIBIO'
      ? `Genial, ${primerNombre}. Le paso tu info al equipo de ventas para que te envien la propuesta. Si aun no tienes el brochure, te lo puedo enviar por WhatsApp o correo ahora mismo.`
      : `Gracias ${primerNombre}. Dejo tu info registrada. Aqui queda mi canal abierto — cuando estes mas cerca de decidir, vuelves cuando quieras.`,
} }];
